mapper.select:
SELECT COUNT(*) FROM projects p JOIN ( SELECT pru.project_code FROM project_role_user pru WHERE pru.user_code = #{userCode}
UNION
SELECT gpr.project_code FROM "GROUP_MEMBER" gm JOIN "GR_PRO_ROLE" gpr ON gpr.gr_code = gm.gr_code WHERE gm.user_code = #{userCode} ) up ON up.project_code = p.project_code JOIN notices n ON n.project_code = p.project_code WHERE p.status = 'OD1' AND p.project_code = #{projectCode}
